/**
 * Live availability check used by the settings UI.
 *
 * ``GET /v1/user/username-available/?username=foo``
 *
 * Response shape (always 200, even when unavailable — the client renders
 * inline state, not a global error):
 *
 * .. code-block:: json
 *
 * {"available": true,  "code": null,        "message": null}
 * {"available": false, "code": "too_short", "message": "Must be at least 3 characters."}
 * {"available": false, "code": "taken",     "message": "This handle is already taken."}
 *
 * A 429 is returned only when the per-user rate cap is exceeded — the
 * request was not evaluated.
 */
export const userUsernameAvailableRetrieveOptions = (options: Options<UserUsernameAvailableRetrieveData>) => queryOptions<UserUsernameAvailableRetrieveResponse, DefaultError, UserUsernameAvailableRetrieveResponse, ReturnType<typeof userUsernameAvailableRetrieveQueryKey>>({
    queryFn: async ({ queryKey, signal }) => {
        const { data } = await userUsernameAvailableRetrieve({
            ...options,
            ...queryKey[0],
            signal,
            throwOnError: true
        });
        return data;
    },
    queryKey: userUsernameAvailableRetrieveQueryKey(options)
});
